    // 2. Trim invisible spaces and force to UPPERCASE
    return {
        json: {
            ...item.json,
            Model_Number: rawModel.toString().trim().toUpperCase(),
            Primary_Manufacturer: rawMfg.toString().trim().toUpperCase(),
            Primary_Product_Type: rawType.toString().trim().toUpperCase()
        }
    };
});

return cleanItems;
